import java.util.Scanner;

public class Solution {

    // Helper function to check for primality
    private static boolean isPrime(long k) {
        if (k <= 1) return false;
        if (k <= 3) return true;
        if (k % 2 == 0 || k % 3 == 0) return false;

        for (long i = 5; i * i <= k; i = i + 6) {
            if (k % i == 0 || k % (i + 2) == 0) {
                return false;
            }
        }
        return true;
    }

    // Helper function to reverse the digits of n
    private static long reverseNumber(long n) {
        long reversed = 0;
        long original = n;
        while (original > 0) {
            int digit = (int) (original % 10);
            reversed = reversed * 10 + digit;
            original /= 10;
        }
        return reversed;
    }

    public static long solve(long n) {
        // 1. Calculate r (reversed n)
        long r = reverseNumber(n);

        // 2. Determine the range [L, R]
        long L = Math.min(n, r);
        long R = Math.max(n, r);

        // 3. Calculate the sum of primes in [L, R]
        long sumOfPrimes = 0;
        for (long i = L; i <= R; i++) {
            if (isPrime(i)) {
                sumOfPrimes += i;
            }
        }

        return sumOfPrimes;
    }
}

